import zugferd_utils
from q2zugferd import q2zugferd_pdf
import os
import re

def get_base64_content(file_path):
    import base64
    with open(file_path, "rb") as f:
        return base64.b64encode(f.read()).decode('utf-8')

def save_base64_to_file(base64_string, output_path):
    import base64
    file_data = base64.b64decode(base64_string)
    with open(output_path, "wb") as f:
        f.write(file_data)


if mem.r.invoice_number == "":
    mem.run_action(_("Set number"))

if mem.r.invoice_number == "":
    return

new_filename =  self.heap.zugferd_files + "\\" + f"{mem.r.invoice_number.replace('/', '_')}.pdf"

if num(mem.r.zugferd_pdf_id) != 0:
    if not os.path.isfile(new_filename):
        content = get("bigcontent", "id=" + mem.r.zugferd_pdf_id, "content")
        if content:
            save_base64_to_file(content, new_filename)
    open_document(new_filename)
else:
    rep = get_report("Invoice-1")
    if rep:
        xml =  get_zugferd_xml(mem.r.id)
        rep.params["id"] = mem.r.id
        pdf_path = rep.run("PDF", open_output_file=0)
        
        q2zugferd_pdf(pdf_path , xml, new_filename)
        bigcontent_record = {"content": get_base64_content(new_filename)}
        if not insert("bigcontent", bigcontent_record):
            q2mess(_("Error saving ZUGFeRD document!"+"<br>"+last_error()))
        else:
            update("invoices", {"id":mem.r.id, "zugferd_pdf_id": bigcontent_record["id"]})
        open_document(new_filename)

