def check_iban(iban):
    if iban=="":
        return True
    iban = iban.replace(" ", "")
    return int("".join([x if x in "0123456789" else str(ord(x)-55) for x in iban[4:]+iban[:4]]))%97==1

def get_bank_data(part_id=4):
    cu = q2cursor(f"""
            select iban, bic_swift, bank_name
            from bank_accounts
            where part_id={part_id}
            order by default_account desc 
            limit 1    
                """)
    if cu.row_count() >0:
        return cu.get_record(0)
    else:
        return {}
                
if __name__ == "__main__":
    ?get_bank_data()

